/**
 * PropertyDataItem
 */
export type PropertyDataItem = {
    /**
     * Name
     */
    name: string;
    /**
     * Address
     */
    address: string;
    /**
     * Listing Url
     * Original listing page URL scraped from the provider site (if available).
     */
    listing_url?: string | null;
    /**
     * City
     * City or locality from the listings row when present (e.g. units.parquet `city`).
     */
    city?: string | null;
    /**
     * State
     * State / region code from the listings row when present (e.g. units.parquet `state`).
     */
    state?: string | null;
    /**
     * Zip Code
     * Postal code from the listings row when present (e.g. units.parquet `zipcode`).
     */
    zip_code?: string | null;
    /**
     * Latitude
     * Latitude of the property if available from the query results.
     */
    latitude?: number | null;
    /**
     * Longitude
     * Longitude of the property if available from the query results.
     */
    longitude?: number | null;
    /**
     * Rent Range
     * rent range from the units available with currency, e.g., $2000-$2500
     */
    rent_range: string;
    /**
     * Bedroom Range
     * bedroom range from the units available, e.g., 1-3 bedrooms
     */
    bedroom_range: string;
    /**
     * Images Urls
     * list of image URLs of the property
     */
    images_urls?: Array<string>;
    /**
     * Main Amenities
     *
     * List of the four main amenities of the property, which should include things related to:
     * - pool
     * - Gym / Fitness center
     * - Parking / Garage
     * - Policies, e.g., pet friendly
     * - Location features, e.g., waterfront, beach access
     * - Building features, e.g., elevator, doorman
     *
     * Maximum of four items.
     * It's important to keep the items concise and avoid full sentences.
     *
     */
    main_amenities: Array<string>;
    /**
     * Amenities
     * list of amenities available in the property
     */
    amenities: Array<string>;
    /**
     * Match Reason
     * One short sentence (max ~200 chars) explaining why this listing matches the user's search (e.g. name/amenities mention 'park', proximity, filters applied).
     */
    match_reason?: string | null;
    /**
     * Validation Status
     * Semantic/LLM validation state for dynamic UI: candidate|validating|confirmed|rejected.
     */
    validation_status?: string | null;
    /**
     * Validation Explanation
     * Short explanation of why the listing is relevant to the current query.
     */
    validation_explanation?: string | null;
    /**
     * Validation Confidence
     * Optional validator confidence in [0,1].
     */
    validation_confidence?: number | null;
    /**
     * Concessions
     * Promotional concession text when present in inventory (e.g. '1 month free').
     */
    concessions?: string | null;
    /**
     * Available Date
     * Earliest move-in / availability label when present in source data.
     */
    available_date?: string | null;
};

